// src/components/article/FormulaManager.jsx
import React, { useState, useEffect } from 'react';

const FormulaManager = ({ isOpen, onClose, onSave, editingBlock, formulaCounter }) => {
  const [formula, setFormula] = useState('');
  const [align, setAlign] = useState('center');
  const [size, setSize] = useState(16);

  useEffect(() => {
    if (editingBlock) {
      setFormula(editingBlock.formulaString || editingBlock.content || '');
      setAlign(editingBlock.align || 'center');
      setSize(editingBlock.size || 16);
    } else {
      setFormula('');
      setAlign('center');
      setSize(16);
    }
  }, [editingBlock]);

  const handleSave = () => {
    if (!formula.trim()) {
      alert('❌ Введите формулу');
      return;
    }

    const formulaData = {
      content: formula,
      formulaString: formula,
      latexString: formula,
      align: align,
      size: size
    };
    onSave(formulaData);
    handleClose();
  };

  const handleClose = () => {
    setFormula('');
    setAlign('center');
    setSize(16);
    onClose();
  };

  if (!isOpen) return null;

  const styles = {
    overlay: {
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      backgroundColor: 'rgba(0, 0, 0, 0.5)',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      zIndex: 1000
    },
    modal: {
      backgroundColor: '#fff',
      padding: '25px',
      borderRadius: '12px',
      width: '500px',
      maxWidth: '90%',
      boxShadow: '0 10px 30px rgba(0,0,0,0.2)'
    },
    title: {
      fontSize: '20px',
      fontWeight: 'bold',
      marginBottom: '20px',
      textAlign: 'center',
      color: '#e67e22'
    },
    formGroup: {
      marginBottom: '15px'
    },
    label: {
      display: 'block',
      marginBottom: '8px',
      fontWeight: 'bold',
      color: '#333'
    },
    textarea: {
      width: '100%',
      padding: '10px',
      border: '1px solid #ddd',
      borderRadius: '8px',
      fontSize: '14px',
      fontFamily: 'monospace',
      resize: 'vertical',
      minHeight: '100px'
    },
    select: {
      width: '100%',
      padding: '8px',
      border: '1px solid #ddd',
      borderRadius: '8px',
      fontSize: '14px'
    },
    sizeControl: {
      display: 'flex',
      alignItems: 'center',
      gap: '10px'
    },
    rangeInput: {
      flex: 1,
      margin: '0 10px'
    },
    preview: {
      marginTop: '15px',
      padding: '15px',
      backgroundColor: '#f8f9fa',
      borderRadius: '8px',
      border: '1px solid #e0e0e0',
      textAlign: align,
      fontSize: `${size}px`,
      fontFamily: 'Times New Roman, serif'
    },
    previewLabel: {
      fontSize: '12px',
      color: '#999',
      marginBottom: '8px'
    },
    buttonGroup: {
      display: 'flex',
      gap: '10px',
      marginTop: '20px'
    },
    saveButton: {
      flex: 1,
      padding: '10px',
      backgroundColor: '#f39c12',
      color: '#fff',
      border: 'none',
      borderRadius: '8px',
      cursor: 'pointer',
      fontSize: '14px',
      fontWeight: 'bold'
    },
    cancelButton: {
      flex: 1,
      padding: '10px',
      backgroundColor: '#95a5a6',
      color: '#fff',
      border: 'none',
      borderRadius: '8px',
      cursor: 'pointer',
      fontSize: '14px',
      fontWeight: 'bold'
    }
  };

  return (
    <div style={styles.overlay} onClick={handleClose}>
      <div style={styles.modal} onClick={(e) => e.stopPropagation()}>
        <h3 style={styles.title}>
          {editingBlock ? '✏️ Редактирование формулы' : '🧮 Создание формулы'}
        </h3>

        <div style={styles.formGroup}>
          <label style={styles.label}>Формула:</label>
          <textarea
            value={formula}
            onChange={(e) => setFormula(e.target.value)}
            placeholder="Примеры: E = mc², ∫ f(x) dx, Σᵢ₌₁ⁿ xᵢ"
            style={styles.textarea}
          />
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Выравнивание:</label>
          <select value={align} onChange={(e) => setAlign(e.target.value)} style={styles.select}>
            <option value="left">По левому краю</option>
            <option value="center">По центру</option>
            <option value="right">По правому краю</option>
          </select>
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Размер: {size}px</label>
          <div style={styles.sizeControl}>
            <span>12px</span>
            <input
              type="range"
              min="12"
              max="48"
              value={size}
              onChange={(e) => setSize(parseInt(e.target.value))}
              style={styles.rangeInput}
            />
            <span>48px</span>
          </div>
        </div>

        {formula && (
          <div style={styles.preview}>
            <div style={styles.previewLabel}>Предпросмотр:</div>
            <div>{formula}</div>
          </div>
        )}

        <div style={styles.buttonGroup}>
          <button onClick={handleSave} style={styles.saveButton}>
            {editingBlock ? '💾 Сохранить' : '➕ Добавить формулу'}
          </button>
          <button onClick={handleClose} style={styles.cancelButton}>
            ✕ Отмена
          </button>
        </div>
      </div>
    </div>
  );
};

export default FormulaManager;
